drop extension if exists "pg_net";

create type "public"."app_role" as enum ('superadmin', 'admin');

create sequence "public"."events_id_seq";


  create table "public"."answers" (
    "id" bigint generated by default as identity not null,
    "response_id" bigint not null,
    "question_id" bigint not null,
    "option_id" bigint,
    "answer_text" text,
    "answer_numeric" integer,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."answers" enable row level security;


  create table "public"."booth_completions" (
    "id" bigint generated by default as identity not null,
    "event_id" bigint not null,
    "quest_id" bigint not null,
    "visitor_id" text not null,
    "completed_at" timestamp with time zone not null default now(),
    "method" text not null default 'pin'::text
      );


alter table "public"."booth_completions" enable row level security;


  create table "public"."event_admins" (
    "event_id" bigint not null,
    "user_id" uuid not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."event_admins" enable row level security;


  create table "public"."event_device_entries" (
    "id" bigint generated by default as identity not null,
    "event_id" bigint not null,
    "visitor_id" text not null,
    "first_seen_at" timestamp with time zone not null default now(),
    "source" text,
    "lang" text,
    "user_agent_hash" text
      );


alter table "public"."event_device_entries" enable row level security;


  create table "public"."events" (
    "id" bigint not null default nextval('public.events_id_seq'::regclass),
    "name" text not null,
    "location" text,
    "start_date" date,
    "end_date" date,
    "created_at" timestamp with time zone not null default now(),
    "is_active" boolean not null default false,
    "story_mode_enabled" boolean not null default true
      );


alter table "public"."events" enable row level security;


  create table "public"."quest" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "event_id" bigint,
    "title" character varying,
    "description" character varying,
    "is_active" boolean,
    "pin" text
      );


alter table "public"."quest" enable row level security;


  create table "public"."question_options" (
    "id" bigint generated by default as identity not null,
    "question_id" bigint not null,
    "option_text" text not null,
    "sort_order" integer default 0,
    "created_at" timestamp with time zone default now(),
    "choice_key" text
      );


alter table "public"."question_options" enable row level security;


  create table "public"."questions" (
    "id" bigint generated by default as identity not null,
    "question_text" text not null,
    "question_type" text not null,
    "category" text,
    "sort_order" integer default 0,
    "is_active" boolean default true,
    "created_at" timestamp with time zone default now(),
    "event_id" bigint not null,
    "dialogue_1_name" text default 'Cell A'::text,
    "dialogue_1_avatar_url" text default '/images/cell1-head.png'::text,
    "dialogue_2_name" text not null default 'Cell B'::text,
    "dialogue_2_avatar_url" text not null default '/images/cell2-head.png'::text,
    "question_tab_name" text default 'Guardian'::text,
    "question_tab_avatar_url" text default '/images/guardian-head.png'::text
      );


alter table "public"."questions" enable row level security;


  create table "public"."responses" (
    "id" bigint generated by default as identity not null,
    "event_id" bigint not null,
    "submitted_at" timestamp with time zone default now()
      );


alter table "public"."responses" enable row level security;


  create table "public"."social_items" (
    "id" bigint generated always as identity not null,
    "section_id" bigint not null,
    "title" text not null,
    "detail" text,
    "url" text not null
      );



  create table "public"."social_sections" (
    "id" bigint generated always as identity not null,
    "title" text not null,
    "display_order" integer not null default 0
      );



  create table "public"."superadmin_emails" (
    "email" text not null
      );


alter table "public"."superadmin_emails" enable row level security;


  create table "public"."user_roles" (
    "user_id" uuid not null,
    "role" public.app_role not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."user_roles" enable row level security;

alter sequence "public"."events_id_seq" owned by "public"."events"."id";

