CREATE OR REPLACE FUNCTION public.assign_admin_by_email(p_email text, p_event_ids bigint[])
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user_id uuid;
  v_event_id bigint;
begin
  if not public.is_superadmin() then
    raise exception 'Only superadmin can assign admins';
  end if;

  select id into v_user_id
  from auth.users
  where lower(email) = lower(trim(p_email))
  limit 1;

  if v_user_id is null then
    raise exception 'User not found for email %', p_email;
  end if;

  insert into public.user_roles(user_id, role)
  values (v_user_id, 'admin')
  on conflict (user_id) do update set role = 'admin';

  foreach v_event_id in array p_event_ids
  loop
    insert into public.event_admins(event_id, user_id)
    values (v_event_id, v_user_id)
    on conflict do nothing;
  end loop;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.assign_initial_role()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  -- If signup email is allowlisted, assign superadmin role
  if exists (
    select 1
    from public.superadmin_emails s
    where lower(s.email) = lower(new.email)
  ) then
    insert into public.user_roles(user_id, role)
    values (new.id, 'superadmin')
    on conflict (user_id) do update set role = excluded.role;
  end if;

  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.can_manage_event(target_event_id bigint)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select
    public.is_superadmin()
    or exists (
      select 1
      from public.event_admins ea
      where ea.event_id = target_event_id
        and ea.user_id = auth.uid()
    );
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_answer_event_match()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  if (select event_id from questions where id = new.question_id) <>
     (select event_id from responses where id = new.response_id) then
    raise exception 'answers.question_id must belong to the same event as responses.event_id';
  end if;
  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_response_event_match()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
declare
  response_event_id bigint;
  question_event_id bigint;
begin
  select event_id into response_event_id
  from responses
  where id = new.response_id;

  select event_id into question_event_id
  from questions
  where id = new.question_id;

  if response_event_id is null or question_event_id is null then
    raise exception 'Invalid response_id or question_id';
  end if;

  if response_event_id <> question_event_id then
    raise exception 'Response/event mismatch';
  end if;

  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.get_feedback_questions_atomic(p_event_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
declare
  v_questions jsonb;
begin
  if p_event_id is null or p_event_id <= 0 then
    raise exception using
      message = 'Invalid event id for feedback question loading.',
      detail = 'Expected a positive event id.',
      hint = 'Provide a valid event id before calling get_feedback_questions_atomic.';
  end if;

  if exists (
    select 1
    from questions q
    where q.event_id = p_event_id
      and q.is_active = true
      and not exists (
        select 1
        from question_options qo
        where qo.question_id = q.id
      )
  ) then
    raise exception using
      message = 'Atomic feedback load failed: one or more active questions are missing options.',
      detail = format('event_id=%s', p_event_id),
      hint = 'Ensure every active question has at least one option before loading feedback.';
  end if;

  select
    coalesce(
      jsonb_agg(
        question_row
        order by question_sort_order nulls last, question_created_at asc, question_id asc
      ),
      '[]'::jsonb
    )
  into v_questions
  from (
    select
      q.id as question_id,
      q.sort_order as question_sort_order,
      q.created_at as question_created_at,
      jsonb_build_object(
        'id', q.id,
        'event_id', q.event_id,
        'question_text', q.question_text,
        'question_type', q.question_type,
        'dialogue_1_text', null,
        'dialogue_1_name', q.dialogue_1_name,
        'dialogue_1_avatar_url', q.dialogue_1_avatar_url,
        'dialogue_2_text', null,
        'dialogue_2_name', q.dialogue_2_name,
        'dialogue_2_avatar_url', q.dialogue_2_avatar_url,
        'question_tab_name', q.question_tab_name,
        'question_tab_avatar_url', q.question_tab_avatar_url,
        'sort_order', q.sort_order,
        'is_active', q.is_active,
        'created_at', q.created_at,
        'options', coalesce(
          (
            select
              jsonb_agg(
                jsonb_build_object(
                  'id', qo.id,
                  'question_id', qo.question_id,
                  'option_text', qo.option_text,
                  'sort_order', qo.sort_order,
                  'choice_key', qo.choice_key,
                  'created_at', qo.created_at
                )
                order by qo.sort_order nulls last, qo.created_at asc, qo.id asc
              )
            from question_options qo
            where qo.question_id = q.id
          ),
          '[]'::jsonb
        )
      ) as question_row
    from questions q
    where q.event_id = p_event_id
      and q.is_active = true
  ) prepared_rows;

  return v_questions;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.get_my_role()
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select ur.role::text
  from public.user_roles ur
  where ur.user_id = auth.uid()
  limit 1;
$function$
;

CREATE OR REPLACE FUNCTION public.is_superadmin()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1
    from public.user_roles ur
    where ur.user_id = auth.uid()
      and ur.role = 'superadmin'
  );
$function$
;

CREATE OR REPLACE FUNCTION public.list_assignable_admin_users()
 RETURNS TABLE(email text)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select lower(u.email)::text as email
  from auth.users u
  where u.email is not null
    and not exists (
      select 1
      from public.user_roles ur
      where ur.user_id = u.id
        and ur.role = 'superadmin'
    )
  order by 1;
$function$
;

CREATE OR REPLACE FUNCTION public.set_event_story_mode(p_event_id bigint, p_story_mode_enabled boolean)
 RETURNS TABLE(id bigint, story_mode_enabled boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  declare
    v_user_id uuid;
    v_role text;
  begin
    v_user_id := auth.uid();

    if v_user_id is null then
      raise exception 'Not authenticated';
    end if;

    select ur.role::text
    into v_role
    from public.user_roles ur
    where ur.user_id = v_user_id
    limit 1;

    if v_role is distinct from 'superadmin' then
      raise exception 'Only superadmin can update story mode';
    end if;

    return query
    update public.events e
    set story_mode_enabled = p_story_mode_enabled
    where e.id = p_event_id
    returning e.id, e.story_mode_enabled;
  end;
  $function$
;

CREATE OR REPLACE FUNCTION public.submit_feedback(p_event_id bigint, p_answers jsonb, p_submitted_at timestamp with time zone DEFAULT now())
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_response_id bigint;
  v_inserted_count integer;
  v_input_count integer;
begin
  if jsonb_typeof(p_answers) <> 'array' then
    raise exception 'p_answers must be a JSON array';
  end if;
  
  if not exists (select 1 from public.events where id = p_event_id) then
    raise exception 'Event % does not exist', p_event_id;
  end if;
  
  if jsonb_array_length(p_answers) = 0 then
    raise exception 'Cannot submit empty feedback';
  end if;

  -- Count input answers early
  v_input_count := jsonb_array_length(p_answers);

  -- Reject duplicate question_id entries
  if exists (
    with parsed_ids as (
      select (x.data->>'question_id')::bigint as question_id
      from jsonb_array_elements(p_answers) as x(data)
      where x.data->>'question_id' is not null
    )
    select 1
    from parsed_ids
    group by question_id
    having count(*) > 1
  ) then
    raise exception 'Duplicate question_id values are not allowed';
  end if;

  insert into public.responses (event_id, submitted_at)
  values (p_event_id, p_submitted_at)
  returning id into v_response_id;
  
  with parsed as (
    select
      (x.data->>'question_id')::bigint as question_id,
      nullif(x.data->>'option_id', '')::bigint as option_id,
      nullif(x.data->>'answer_text', '') as answer_text,
      nullif(x.data->>'answer_numeric', '')::integer as answer_numeric,
      coalesce(nullif(x.data->>'created_at', '')::timestamptz, p_submitted_at) as created_at
    from jsonb_array_elements(p_answers) as x(data)
  ),
  validated as (
    select p.*
    from parsed p
    join public.questions q
      on q.id = p.question_id
     and q.event_id = p_event_id
    left join public.question_options qo
      on qo.id = p.option_id
     and qo.question_id = p.question_id
    where p.question_id is not null
      and (p.option_id is null or qo.id is not null)
  )
  insert into public.answers (
    response_id, question_id, option_id, answer_text, answer_numeric, created_at
  )
  select
    v_response_id,
    question_id,
    option_id,
    answer_text,
    answer_numeric,
    created_at
  from validated;
  
  get diagnostics v_inserted_count = row_count;
  
  -- Fail if any answers were rejected
  if v_inserted_count <> v_input_count then
    raise exception 'Invalid answers detected: % provided, only % valid. All answers must be valid for event %', 
      v_input_count, v_inserted_count, p_event_id;
  end if;
  
  if v_inserted_count = 0 then
    raise exception 'No valid answers provided for event %', p_event_id;
  end if;
  
  return v_response_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.update_question_with_options_atomic(p_question_id bigint, p_question_text text, p_question_type text, p_options jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
declare
  v_trimmed_question_text text;
  v_trimmed_question_type text;
  v_option_count integer;
  v_empty_option_count integer;
  v_invalid_choice_count integer;
  v_duplicate_choice_count integer;
  v_duplicate_sort_count integer;
  v_invalid_option_id_count integer;
  v_duplicate_option_id_count integer;
  v_existing_option_ids bigint[];
  v_inserted_option_ids bigint[];
  v_keep_option_ids bigint[];
  v_question_row questions%rowtype;
begin
  if p_question_id is null or p_question_id <= 0 then
    raise exception using
      message = 'Invalid question id.',
      detail = 'p_question_id must be a positive integer.';
  end if;

  v_trimmed_question_text := btrim(coalesce(p_question_text, ''));
  if v_trimmed_question_text = '' then
    raise exception using
      message = 'Question text cannot be empty.';
  end if;

  v_trimmed_question_type := btrim(coalesce(p_question_type, ''));
  if v_trimmed_question_type = '' then
    raise exception using
      message = 'Question type cannot be empty.';
  end if;

  if v_trimmed_question_type not in ('text', 'rating', 'yes_no', 'mcq') then
    raise exception using
      message = format('Invalid question type: %s', v_trimmed_question_type),
      hint = 'Use one of: text, rating, yes_no, mcq.';
  end if;

  if p_options is null or jsonb_typeof(p_options) <> 'array' then
    raise exception using
      message = 'Options payload must be a JSON array.';
  end if;

  select count(*)
  into v_option_count
  from jsonb_array_elements(p_options);

  if v_option_count <> 2 then
    raise exception using
      message = 'Exactly 2 options are required.',
      detail = format('Received %s option(s).', v_option_count),
      hint = 'Provide one option for Cell A and one option for Cell B.';
  end if;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id,
      btrim(coalesce(item.value->>'option_text', '')) as option_text,
      upper(btrim(coalesce(item.value->>'choice_key', ''))) as choice_key,
      case
        when coalesce(item.value->>'sort_order', '') ~ '^-?[0-9]+$' then (item.value->>'sort_order')::integer
        else item.ordinality::integer - 1
      end as sort_order
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  )
  select count(*)
  into v_empty_option_count
  from parsed_options
  where option_text = '';

  if v_empty_option_count > 0 then
    raise exception using
      message = 'Option text cannot be empty.';
  end if;

  with parsed_options as (
    select
      upper(btrim(coalesce(item.value->>'choice_key', ''))) as choice_key
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  )
  select count(*)
  into v_invalid_choice_count
  from parsed_options
  where choice_key not in ('A', 'B');

  if v_invalid_choice_count > 0 then
    raise exception using
      message = 'Each option must be assigned to A or B.';
  end if;

  with parsed_options as (
    select
      upper(btrim(coalesce(item.value->>'choice_key', ''))) as choice_key
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  ),
  duplicate_choices as (
    select choice_key
    from parsed_options
    group by choice_key
    having count(*) > 1
  )
  select count(*)
  into v_duplicate_choice_count
  from duplicate_choices;

  if v_duplicate_choice_count > 0 then
    raise exception using
      message = 'Options must have unique A and B assignments.';
  end if;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'sort_order', '') ~ '^-?[0-9]+$' then (item.value->>'sort_order')::integer
        else item.ordinality::integer - 1
      end as sort_order
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  ),
  duplicate_sort_orders as (
    select sort_order
    from parsed_options
    group by sort_order
    having count(*) > 1
  )
  select count(*)
  into v_duplicate_sort_count
  from duplicate_sort_orders;

  if v_duplicate_sort_count > 0 then
    raise exception using
      message = 'Option order contains duplicates.';
  end if;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  )
  select count(*)
  into v_invalid_option_id_count
  from parsed_options p
  where p.id is not null
    and not exists (
      select 1
      from question_options qo
      where qo.id = p.id
        and qo.question_id = p_question_id
    );

  if v_invalid_option_id_count > 0 then
    raise exception using
      message = 'One or more option ids do not belong to this question.';
  end if;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  ),
  duplicate_ids as (
    select id
    from parsed_options
    where id is not null
    group by id
    having count(*) > 1
  )
  select count(*)
  into v_duplicate_option_id_count
  from duplicate_ids;

  if v_duplicate_option_id_count > 0 then
    raise exception using
      message = 'Duplicate option ids were provided in the request.';
  end if;

  select *
  into v_question_row
  from questions q
  where q.id = p_question_id
  for update;

  if not found then
    raise exception using
      message = 'Question not found.',
      detail = format('question_id=%s', p_question_id);
  end if;

  update questions
  set
    question_text = v_trimmed_question_text,
    question_type = v_trimmed_question_type
  where id = p_question_id
  returning *
  into v_question_row;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id,
      btrim(coalesce(item.value->>'option_text', '')) as option_text,
      upper(btrim(coalesce(item.value->>'choice_key', ''))) as choice_key,
      case
        when coalesce(item.value->>'sort_order', '') ~ '^-?[0-9]+$' then (item.value->>'sort_order')::integer
        else item.ordinality::integer - 1
      end as sort_order
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  )
  update question_options qo
  set
    option_text = p.option_text,
    sort_order = p.sort_order,
    choice_key = p.choice_key
  from parsed_options p
  where p.id is not null
    and qo.id = p.id
    and qo.question_id = p_question_id;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  )
  select coalesce(array_agg(id), '{}'::bigint[])
  into v_existing_option_ids
  from parsed_options
  where id is not null;

  with parsed_options as (
    select
      case
        when coalesce(item.value->>'id', '') ~ '^[0-9]+$' then (item.value->>'id')::bigint
        else null
      end as id,
      btrim(coalesce(item.value->>'option_text', '')) as option_text,
      upper(btrim(coalesce(item.value->>'choice_key', ''))) as choice_key,
      case
        when coalesce(item.value->>'sort_order', '') ~ '^-?[0-9]+$' then (item.value->>'sort_order')::integer
        else item.ordinality::integer - 1
      end as sort_order
    from jsonb_array_elements(p_options) with ordinality as item(value, ordinality)
  ),
  inserted as (
    insert into question_options (question_id, option_text, sort_order, choice_key)
    select
      p_question_id,
      p.option_text,
      p.sort_order,
      p.choice_key
    from parsed_options p
    where p.id is null
    returning id
  )
  select coalesce(array_agg(id), '{}'::bigint[])
  into v_inserted_option_ids
  from inserted;

  v_keep_option_ids := coalesce(v_existing_option_ids, '{}'::bigint[]) || coalesce(v_inserted_option_ids, '{}'::bigint[]);

  delete from question_options qo
  where qo.question_id = p_question_id
    and not (qo.id = any(v_keep_option_ids));

  return jsonb_build_object(
    'question',
    to_jsonb(v_question_row),
    'options',
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'id', qo.id,
            'question_id', qo.question_id,
            'option_text', qo.option_text,
            'sort_order', qo.sort_order,
            'choice_key', qo.choice_key,
            'created_at', qo.created_at
          )
          order by qo.sort_order nulls last, qo.created_at asc, qo.id asc
        )
        from question_options qo
        where qo.question_id = p_question_id
      ),
      '[]'::jsonb
    )
  );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_booth_completion_event_match()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  if not exists (
    select 1
    from public.quest q
    where q.id = new.quest_id
      and q.event_id = new.event_id
  ) then
    raise exception 'quest_id % does not belong to event_id %', new.quest_id, new.event_id;
  end if;

  return new;
end;
$function$
;

