  create policy "Allow anonymous inserts on answers"
  on "public"."answers"
  as permissive
  for insert
  to anon
with check (true);



  create policy "answers_superadmin_all"
  on "public"."answers"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.user_roles ur
  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))))
with check ((EXISTS ( SELECT 1
   FROM public.user_roles ur
  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))));



  create policy "event_admins_read"
  on "public"."event_admins"
  as permissive
  for select
  to authenticated
using (((user_id = auth.uid()) OR public.is_superadmin()));



  create policy "event_admins_write"
  on "public"."event_admins"
  as permissive
  for all
  to authenticated
using (public.is_superadmin())
with check (public.is_superadmin());



  create policy "events_delete_superadmin_only"
  on "public"."events"
  as permissive
  for delete
  to authenticated
using (public.is_superadmin());



  create policy "events_insert_admin_or_superadmin"
  on "public"."events"
  as permissive
  for insert
  to authenticated
with check ((public.is_superadmin() OR (EXISTS ( SELECT 1
   FROM public.user_roles ur
  WHERE ((ur.user_id = auth.uid()) AND (ur.role = 'admin'::public.app_role))))));



  create policy "events_select_assigned_or_superadmin"
  on "public"."events"
  as permissive
  for select
  to authenticated
using (public.can_manage_event(id));



  create policy "events_superadmin_all"
  on "public"."events"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.user_roles ur
  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))))
with check ((EXISTS ( SELECT 1
   FROM public.user_roles ur
  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))));



  create policy "events_update_assigned_or_superadmin"
  on "public"."events"
  as permissive
  for update
  to authenticated
using (public.can_manage_event(id))
with check (public.can_manage_event(id));



  create policy "allow_public_view_quest"
  on "public"."quest"
  as permissive
  for select
  to public
using (true);



  create policy "quest_superadmin_all"
  on "public"."quest"
