  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))));



  create policy "Allow public read on question_options"
  on "public"."question_options"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "question_options_superadmin_all"
  on "public"."question_options"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.user_roles ur
