  WHERE ((ur.user_id = auth.uid()) AND ((ur.role)::text = 'superadmin'::text)))));



  create policy "Allow public read on questions"
  on "public"."questions"
  as permissive
  for select
  to anon
using ((is_active = true));



  create policy "questions_manage_assigned_or_superadmin"
  on "public"."questions"
  as permissive
  for all
  to authenticated
using (public.can_manage_event(event_id))
with check (public.can_manage_event(event_id));



