CREATE TRIGGER trg_enforce_answer_event BEFORE INSERT OR UPDATE ON public.answers FOR EACH ROW EXECUTE FUNCTION public.enforce_answer_event_match();

CREATE TRIGGER trg_enforce_response_event BEFORE INSERT OR UPDATE ON public.answers FOR EACH ROW EXECUTE FUNCTION public.enforce_response_event_match();

CREATE TRIGGER trg_validate_booth_completion_event_match BEFORE INSERT OR UPDATE ON public.booth_completions FOR EACH ROW EXECUTE FUNCTION public.validate_booth_completion_event_match();

CREATE TRIGGER trg_assign_initial_role AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.assign_initial_role();


